func (i CreateAppSecretInput) Validate() error {
    if err := i.AppID.Validate(); err != nil {
        return models.NewGenericValidationError(errors.New("app id is invalid"))
    }
    if i.Key == "" { return models.NewGenericValidationError(errors.New("key is required")) }
    return nil
}

type SecretID struct {
    models.NamespacedID
    AppID app.AppID
    Key   string
}

var _ models.GenericError = (*SecretNotFoundError)(nil)
func NewSecretNotFoundError(id SecretID) *SecretNotFoundError {
    return &SecretNotFoundError{err: models.NewGenericNotFoundError(fmt.Errorf("app with id %s not found", id.ID))}
}

func New(config Config) (*Service, error) {
    if err := config.Validate(); err != nil { return nil, err }
    return &Service{adapter: config.Adapter}, nil
}

// service.go
var _ secret.Service = (*Service)(nil)
// secret.go
var _ secret.SecretService = (*Service)(nil)

func (s *Service) CreateAppSecret(ctx context.Context, input secretentity.CreateAppSecretInput) (secretentity.SecretID, error) {
    if err := input.Validate(); err != nil {
        return secretentity.SecretID{}, models.NewGenericValidationError(fmt.Errorf("error create app secret: %w", err))
    }
    return s.adapter.CreateAppSecret(ctx, input)
}

